import{_ as t,j as n,o as h,v as a}from"./chunks/framework.dn0DPyqd.js";const o=JSON.parse('{"title":"Chúng tôi đã bị tấn công, phòng thủ thành công nhưng có status đặc biệt cần điều tra","description":"Design Pattern tập trung vào giải pháp tái sử dụng cho các vấn đề thiết kế cụ thể ở mức độ function, class và project. Software Architecture định nghĩa cấu trúc tổng thể của hệ thống, từ mức độ project đến solution và system.","frontmatter":{"footer":true,"title":"Chúng tôi đã bị tấn công, phòng thủ thành công nhưng có status đặc biệt cần điều tra","description":"Design Pattern tập trung vào giải pháp tái sử dụng cho các vấn đề thiết kế cụ thể ở mức độ function, class và project. Software Architecture định nghĩa cấu trúc tổng thể của hệ thống, từ mức độ project đến solution và system.","authors":["lethanh"],"date":"2024-11-01T00:00:00.000Z","outline":"deep","draft":false},"headers":[{"level":2,"title":"Thời điểm bị tấn công","slug":"thoi-điem-bi-tan-cong","link":"#thoi-điem-bi-tan-cong","children":[]},{"level":2,"title":"Họ đã tấn công chúng tôi như thế nào ?","slug":"ho-đa-tan-cong-chung-toi-nhu-the-nao","link":"#ho-đa-tan-cong-chung-toi-nhu-the-nao","children":[]},{"level":2,"title":"Trong quá trình giám sát chúng tôi đã nhóm hacker đã thực hiện tấn công DDoS và bảo mật. Họ đã sử dụng một số kỹ thuật sau:","slug":"trong-qua-trinh-giam-sat-chung-toi-đa-nhom-hacker-đa-thuc-hien-tan-cong-ddos-va-bao-mat-ho-đa-su-dung-mot-so-ky-thuat-sau","link":"#trong-qua-trinh-giam-sat-chung-toi-đa-nhom-hacker-đa-thuc-hien-tan-cong-ddos-va-bao-mat-ho-đa-su-dung-mot-so-ky-thuat-sau","children":[]},{"level":2,"title":"Phòng thủ","slug":"phong-thu","link":"#phong-thu","children":[]}],"relativePath":"short-blog/2024-11-01-chung-toi-da-bi-tan-cong-phong-thu-thanh-cong-nhung-co-status-dac-biet-can-dieu-tra.md","filePath":"short-blog/2024-11-01-chung-toi-da-bi-tan-cong-phong-thu-thanh-cong-nhung-co-status-dac-biet-can-dieu-tra.md","lastUpdated":1730445907000}'),c={name:"short-blog/2024-11-01-chung-toi-da-bi-tan-cong-phong-thu-thanh-cong-nhung-co-status-dac-biet-can-dieu-tra.md"},g=[a('<p>Xin chào mọi người, đây là bài đầu tiên của Short Blog. Thực tế sau sự kiện này xảy ra thì tôi đã nghĩ đến ý tưởng viết Short blog :v.</p><h2 id="thoi-điem-bi-tan-cong" tabindex="-1">Thời điểm bị tấn công <a class="header-anchor" href="#thoi-điem-bi-tan-cong" aria-label="Permalink to &quot;Thời điểm bị tấn công&quot;">​</a></h2><p>Ứng dụng của chúng tôi là một ứng dụng lớn có nhiều người truy cập hàng ngày với hơn 4 tỉ bản ghi dữ liệu chính(Core Dataset). Vào một ngày khi mọi người đang ngủ ngon, hệ thống của chúng tôi bị tấn công DDoS và bảo mật.</p><p>Cụ thể là vào khoản từ <strong>1h sáng đến 5h sáng</strong>, hệ thống của chúng tôi bị tấn công DDoS và bảo mật. Tuy nhiên, các thành viên trong team đã nhận được cảnh báo số lượng request tăng đột biến và những param,header lạ và đã thức dậy để giám sát hệ thống.</p><h2 id="ho-đa-tan-cong-chung-toi-nhu-the-nao" tabindex="-1">Họ đã tấn công chúng tôi như thế nào ? <a class="header-anchor" href="#ho-đa-tan-cong-chung-toi-nhu-the-nao" aria-label="Permalink to &quot;Họ đã tấn công chúng tôi như thế nào ?&quot;">​</a></h2><h2 id="trong-qua-trinh-giam-sat-chung-toi-đa-nhom-hacker-đa-thuc-hien-tan-cong-ddos-va-bao-mat-ho-đa-su-dung-mot-so-ky-thuat-sau" tabindex="-1">Trong quá trình giám sát chúng tôi đã nhóm hacker đã thực hiện tấn công DDoS và bảo mật. Họ đã sử dụng một số kỹ thuật sau: <a class="header-anchor" href="#trong-qua-trinh-giam-sat-chung-toi-đa-nhom-hacker-đa-thuc-hien-tan-cong-ddos-va-bao-mat-ho-đa-su-dung-mot-so-ky-thuat-sau" aria-label="Permalink to &quot;Trong quá trình giám sát chúng tôi đã nhóm hacker đã thực hiện tấn công DDoS và bảo mật. Họ đã sử dụng một số kỹ thuật sau:&quot;">​</a></h2><h2 id="phong-thu" tabindex="-1">Phòng thủ <a class="header-anchor" href="#phong-thu" aria-label="Permalink to &quot;Phòng thủ&quot;">​</a></h2><p>Với tư duy <code>Không phải hệ thống của chúng ta có bị tấn công hay không, mà là khi nào hệ thống của chúng ta bị tấn công</code>. Chúng tôi đã chuẩn bị rất nhiều kế hoạch phòng thủ cho trường hợp này.</p>',8)];const i=t(c,[["render",function(t,a,o,c,i,e){return h(),n("div",null,g)}]]);export{o as __pageData,i as default};
